with ins as (
  insert into core.control_evaluation_catalog (
    id,
    control_id,
    dimension_id,
    code,
    title,
    evaluation_guidance,
    pass_criteria,
    fail_criteria,
    evaluator_steps,
    evidence_required,
    evidence_min_spec,
    sample_guidance,
    notes,
    status,
    is_active,
    framework_version_id,
    effective_from,
    effective_to,
    created_at,
    updated_at
  )
  select
    t.id::uuid,
    t.control_id::uuid,
    'c288a358-ef38-4c64-960b-43fffb9a3412'::uuid as dimension_id,
    t.code,
    t.title,
    t.evaluation_guidance,
    t.pass_criteria,
    t.fail_criteria,
    t.evaluator_steps::jsonb,
    t.evidence_required,
    t.evidence_min_spec,
    t.sample_guidance,
    t.notes,
    t.status,
    t.is_active::boolean,
    t.framework_version_id::uuid,
    t.effective_from::timestamptz,
    t.effective_to::timestamptz,
    t.created_at::timestamptz,
    t.updated_at::timestamptz
  from tmp_cyb_group_8_9 t
  where not exists (
    select 1
    from core.control_evaluation_catalog c
    where c.id = t.id::uuid
       or c.code = t.code
  )
  returning 1
)
select count(*) as inserted_rows
from ins;

